def main():
    # 生成 country_data.js
    lines = ['// 国家基本信息（内嵌，无需外部API）', 'const countryInfo = {']
    for cid in sorted(COUNTRIES_INFO.keys()):
        info = COUNTRIES_INFO[cid]
        d = info['d'].replace("'", "\\'")
        line = f"  '{cid}': {{ name: '{info['n']}', official: '{info['o']}', flag: '{info['f']}', capital: '{info['c']}', region: '{info['r']}', pop: '{info['p']}', area: '{info['a']}', lang: '{info['l']}', currency: '{info['m']}', tz: '{info['t']}', drive: '{d}', borders: '{info['b']}' }},"
        lines.append(line)
    lines.append('};')
    js = '\n'.join(lines)

    path = r'C:\Users\OseasyVM\.openclaw\workspace\industry-news-website\docs\country_data.js'
    with open(path, 'w', encoding='utf-8') as f:
        f.write(js)
    print(f'✅ 生成 {path}')
    print(f'   大小: {len(js)} 字节, {len(COUNTRIES_INFO)} 个国家')

if __name__ == '__main__':
    main()
